    23→        return lastSaveTime ? formatDistanceToNow(lastSaveTime, { addSuffix: true }) : 'Saved';
    24→      case 'error':
    25→        return 'Failed';
    26→      default:
    27→        return 'Saved';
    28→    }
    29→  };
    30→
    31→  return (
    32→    <>
    33→      {/* Main Footer - Bottom Left with Links */}
